<?php
declare(strict_types=1);
namespace Oasebos\Participations\Services;
use Oasebos\Participations\Database\Repository;
final class DonationService { public function __construct(private ?Repository $repo=null){$this->repo??=new Repository();} public function createPending(array $d): int { return $this->repo->insert('donations',['donation_number'=>(new NumberGenerator($this->repo))->generate('donation'),'donor_first_name'=>$d['first_name']??'','donor_last_name'=>$d['last_name']??'','donor_email'=>$d['email'],'amount'=>$d['amount'],'currency'=>'EUR','message'=>$d['message']??'','status'=>'pending']); } public function markPaid(int $id,string $paymentId=''):void{$d=$this->repo->get('donations',$id); if(!$d||$d['status']==='paid')return; $this->repo->update('donations',$id,['status'=>'paid','mollie_payment_id'=>$paymentId?:$d['mollie_payment_id'],'paid_at'=>current_time('mysql')]); $email=new EmailService($this->repo); $email->send('donation',$id,$d['donor_email'],__('Bedankt voor je donatie aan Oasebos','oasebos-participations'),$this->emailHtml($d),[],$this->context($d),'donation_paid'); $email->sendAdmin('donation',$id,__('Nieuwe donatie ontvangen','oasebos-participations'),$this->adminEmailHtml($d),$this->context($d),'admin_donation_paid'); } public function resendConfirmation(int $id): bool { $d=$this->repo->get('donations',$id); if(!$d)return false; return (new EmailService($this->repo))->send('donation',$id,$d['donor_email'],__('Bedankt voor je donatie aan Oasebos','oasebos-participations'),$this->emailHtml($d),[],$this->context($d),'donation_paid'); } private function context(array $d): array { return ['donation_number'=>$d['donation_number']??'','donor_first_name'=>$d['donor_first_name']??'','donor_last_name'=>$d['donor_last_name']??'','donor_email'=>$d['donor_email']??'','currency'=>$d['currency']??'EUR','amount'=>number_format_i18n((float)($d['amount']??0),2)]; } private function emailHtml(array $d): string { return '<p>Beste '.esc_html((string)$d['donor_first_name']).',</p><p>Hartelijk dank voor je donatie aan Stichting Oasebos.</p><p><strong>Donatienummer:</strong> '.esc_html((string)$d['donation_number']).'<br><strong>Bedrag:</strong> '.esc_html((string)$d['currency']).' '.esc_html(number_format_i18n((float)$d['amount'],2)).'</p><p>Met jouw steun kunnen we natuur beschermen en herstellen.</p><p>Met groene groet,<br>Stichting Oasebos</p>'; } private function adminEmailHtml(array $d): string { return '<p>Er is een nieuwe donatie ontvangen.</p><p><strong>Donatienummer:</strong> '.esc_html((string)$d['donation_number']).'<br><strong>Naam:</strong> '.esc_html(trim((string)$d['donor_first_name'].' '.(string)$d['donor_last_name'])).'<br><strong>E-mail:</strong> '.esc_html((string)$d['donor_email']).'<br><strong>Bedrag:</strong> '.esc_html((string)$d['currency']).' '.esc_html(number_format_i18n((float)$d['amount'],2)).'</p>'; } }
